Here's how to handle draft persistence using MAUI's lifecycle events and `Preferences`:

**1. In your `NotePage.xaml.cs`:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();

        // Subscribe to lifecycle events
        App.Current.Windows[0].Resumed += OnResumed;
        App.Current.Windows[0].Stopped += OnStopped;
        App.Current.Windows[0].Deactivated += OnDeactivated;
    }

    private void OnDeactivated(object sender, EventArgs e)
    {
        SaveDraft();
    }

    private void OnStopped(object sender, EventArgs e)
    {
        SaveDraft();
    }

    private void OnResumed(object sender, EventArgs e)
    {
        RestoreDraft();
    }

    private void SaveDraft()
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void RestoreDraft()
    {
        string draft = Preferences.Get(DraftKey, string.Empty);
        if (!string.IsNullOrEmpty(draft))
            NoteEditor.Text = draft;
    }

    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }

    // Clean up when page is removed from navigation
    protected override void OnDisappearing()
    {
        base.OnDisappearing();
        App.Current.Windows[0].Resumed -= OnResumed;
        App.Current.Windows[0].Stopped -= OnStopped;
        App.Current.Windows[0].Deactivated -= OnDeactivated;
    }
}
```

**2. In your `NotePage.xaml`:**

```xml
<Editor x:Name="NoteEditor" Placeholder="Start typing your note..." />
```

**Key points:**

- **`Deactivated`** — fires when the app loses focus (covers background + multitasking)
- **`Stopped`** — fires when the app is fully backgrounded
- **`Resumed`** — fires when the app returns to foreground
- **`Preferences`** — lightweight key-value store, ideal for small text; for large drafts use `SecureStorage` or file I/O
- Call **`ClearDraft()`** after the user explicitly saves/discards the note
- Always **unsubscribe** from events in `OnDisappearing` to avoid leaks
